/// <summary>
/// Motivo pelo qual uma habilidade está a ser cancelada centralmente (item 8 da
/// auditoria — "IAbility + cancelamento"). Usado por <see cref="IAbility.Cancel"/>
/// e por <see cref="AbilityRouter.CancelAll"/> para que cada habilidade possa, se
/// quiser, reagir de forma diferente conforme o motivo (ex: tocar um som de
/// "largar" só quando é o jogador a soltar por opção própria, e não ao morrer).
/// Na prática, todas as implementações actuais tratam qualquer motivo da mesma
/// forma (paragem imediata, sem efeitos extra) — o enum existe para permitir essa
/// diferenciação no futuro sem mudar a assinatura.
/// </summary>
public enum AbilityCancelReason
{
    /// <summary>O jogador transformou-se noutro animal (FormSwitcher.ApplyForm).</summary>
    Transform,

    /// <summary>O jogador morreu (PlayerProgress.OnHeartsDepleted).</summary>
    Death,

    /// <summary>Um diálogo com NPC foi aberto.</summary>
    Dialogue,

    /// <summary>Uma cutscene foi iniciada.</summary>
    Cutscene,

    /// <summary>Um menu (pausa, mapa, etc.) foi aberto.</summary>
    MenuOpened,

    /// <summary>O jogador ficou preso numa armadilha/efeito que bloqueia o movimento.</summary>
    Trapped,

    /// <summary>O jogador saiu da água (deixou de estar submerso/dentro de água).</summary>
    LeftWater,

    /// <summary>Uma nova cena vai ser carregada.</summary>
    SceneLoad,
}

/// <summary>
/// Contrato comum a habilidades "com estado" (que podem ficar activas durante
/// vários frames e precisam de ser interrompidas de fora — item 8 da auditoria).
///
/// Nem todas as ~19 habilidades do projecto precisam de implementar isto: muitas
/// (Roll, Egg, HeavyStrike, Roar, Sonar, Charge sem hold, etc.) são "instantâneas"
/// — disparam um efeito de curta duração com o próprio cooldown interno e não
/// deixam o player num estado que precise de ser cancelado de fora. Para essas,
/// não implementar IAbility está bem.
///
/// Implementar IAbility faz sentido para habilidades que:
/// - bloqueiam o movimento normal (motor.SetMovementLocked) enquanto activas
///   (Climb, Dash, Swing, TonguePull, ShellGuard), ou
/// - colocam o player num estado persistente que outro sistema pode precisar de
///   interromper (GrabThrow — a carregar um objecto).
///
/// "Activate"/"Release" mapeiam para o botão de habilidade (ver AbilityRouter,
/// OnAbilityPressed/OnAbilityReleased) quando essa habilidade já é controlada por
/// esse botão. Para habilidades cujo gatilho é outro (Climb/Swing via Interagir,
/// GrabThrow automático em Update) estes métodos podem ser no-ops — o que importa
/// para o cancelamento central é <see cref="Cancel"/> e <see cref="IsActive"/>.
/// </summary>
public interface IAbility
{
    /// <summary>Tenta iniciar/activar a habilidade (equivalente a premir o botão de habilidade).</summary>
    void Activate();

    /// <summary>Reage a soltar o botão de habilidade, para habilidades do tipo "hold".</summary>
    void Release();

    /// <summary>
    /// Interrompe imediatamente a habilidade se estiver activa, restaurando
    /// movimento/gravidade/etc. Chamado por <see cref="AbilityRouter.CancelAll"/>.
    /// Deve ser seguro chamar mesmo que a habilidade já esteja inactiva (no-op).
    /// </summary>
    void Cancel(AbilityCancelReason reason);

    /// <summary>Tempo restante (segundos) até a habilidade poder ser activada de novo. 0 se não tiver cooldown ou já estiver disponível.</summary>
    float CooldownRemaining { get; }

    /// <summary>True enquanto a habilidade está num estado activo/persistente que ocupa o player (ex: a escalar, a balançar, a carregar um objecto).</summary>
    bool IsActive { get; }
}
